diffPreview:
- else if (update.message?.text) {
+ else if (update.message) {
    this.handleIncomingMessage(update.message)...
  }

- if (!msg || !msg.text) return;
+ if (!msg) return;
+ const rawText = String(msg.text || msg.caption || '').trim();
+ const hasPhoto = Array.isArray(msg.photo) && msg.photo.length > 0;
+ const hasImageDocument = this.isImageDocument(msg.document);
+ const hasImage = hasPhoto || hasImageDocument;

+ // On image message: resolve file via getFile, download bytes, attach data_url in callerContext
+ const imageContextBlock = hasImage ? `INBOUND_TELEGRAM_IMAGE: true ... data_url=...` : '';
+ const callerContext = imageContextBlock ? `${baseContext}\n${imageContextBlock}` : baseContext;

